class Car {       // The class
  public:             // Access specifier
    int myNum;        // Attribute (int variable)
    string myString;  // Attribute (string variable)
};

class Car { 
  public:
    int year;
    string brand;
};

int main() {
  Car myObj;  // Create an object of Car named myObj

  // Access attributes and set values
  myObj.year = 1969;
  myObj.brand = "Ford";

  // Print attribute values
  cout << myObj.year << " " << myObj.brand;
  return 0;
}
